const script = document.createElement('script'); script.src = 'https://cdn.jsdelivr.net/npm/molstar@5.11.0/build/viewer/molstar.js';
await new Promise((ok, bad) => { script.onload = ok; script.onerror = bad; document.head.appendChild(script); });
const el = document.createElement('div'); el.style.cssText = 'position:relative;height:520px'; shadowRoot.appendChild(el);
const viewer = await window.molstar.Viewer.create(el);
